mapper.select:
SELECT n.id, n.title, n.content, n.type, n.status, n.priority, n.publisher_name, n.publish_time, n.view_count, n.expire_time, n.scheduled_time FROM notice n
AND (n.title LIKE CONCAT('%', #{query.keyword}, '%') OR n.content LIKE CONCAT('%', #{query.keyword}, '%'))
AND n.type = #{query.type}
AND n.status = #{query.status}
AND DATE(n.publish_time) = #{query.publishDate}
ORDER BY n.publish_time DESC, n.create_time DESC
